typedef float fp;

__kernel void extract_kernel(const long d_Ne,
                             __global fp *d_I)
{
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / 255.0f);
    }
}

__kernel void prepare_kernel(const long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2)
{
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        fp v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(const long d_Ne,
                            const long d_no,
                            const int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            const int d_blocks)
{
    (void)d_Ne;
    (void)d_blocks;

    const long bx = (long)get_group_id(0);
    const long tx = (long)get_local_id(0);
    const long lsize = (long)get_local_size(0);
    const long start = bx * lsize;

    if (tx == 0 && start < d_no) {
        fp sum = 0.0f;
        fp sum2 = 0.0f;
        long end = start + lsize;
        if (end > d_no) end = d_no;

        for (long i = start; i < end; i++) {
            fp v1 = d_sums[i * (long)d_mul];
            fp v2 = d_sums2[i * (long)d_mul];
            sum += v1;
            sum2 += v2;
        }

        d_sums[bx * lsize * (long)d_mul] = sum;
        d_sums2[bx * lsize * (long)d_mul] = sum2;
    }
}

__kernel void srad_kernel(const fp lambda,
                          const int Nr,
                          const int Nc,
                          const long Ne,
                          __global int *d_iN,
                          __global int *d_iS,
                          __global int *d_jE,
                          __global int *d_jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          const fp q0sqr,
                          __global fp *d_c,
                          __global fp *d_I)
{
    (void)lambda;
    (void)Nr;

    long k = (long)get_global_id(0);
    if (k < Ne) {
        int i = (int)(k / (long)Nc);
        int j = (int)(k % (long)Nc);

        fp Jc = d_I[k];

        fp dN = d_I[(long)d_iN[i] * (long)Nc + j] - Jc;
        fp dS = d_I[(long)d_iS[i] * (long)Nc + j] - Jc;
        fp dW = d_I[(long)i * (long)Nc + d_jW[j]] - Jc;
        fp dE = d_I[(long)i * (long)Nc + d_jE[j]] - Jc;

        d_dN[k] = dN;
        d_dS[k] = dS;
        d_dW[k] = dW;
        d_dE[k] = dE;

        fp G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
        fp L = (dN + dS + dW + dE) / Jc;

        fp num = 0.5f * G2 - 0.0625f * (L * L);
        fp den = 1.0f + 0.25f * L;
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        fp c = 1.0f / (1.0f + den);

        if (c < 0.0f) c = 0.0f;
        else if (c > 1.0f) c = 1.0f;

        d_c[k] = c;
    }
}

__kernel void srad2_kernel(const fp lambda,
                           const int Nr,
                           const int Nc,
                           const long Ne,
                           __global int *d_iN,
                           __global int *d_iS,
                           __global int *d_jE,
                           __global int *d_jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I)
{
    (void)Nr;
    (void)d_iN;
    (void)d_jW;

    long k = (long)get_global_id(0);
    if (k < Ne) {
        int i = (int)(k / (long)Nc);
        int j = (int)(k % (long)Nc);

        fp cN = d_c[k];
        fp cS = d_c[(long)d_iS[i] * (long)Nc + j];
        fp cW = d_c[k];
        fp cE = d_c[(long)i * (long)Nc + d_jE[j]];

        fp D = cN * d_dN[k] + cS * d_dS[k] + cW * d_dW[k] + cE * d_dE[k];

        d_I[k] = d_I[k] + 0.25f * lambda * D;
    }
}

__kernel void compress_kernel(const long d_Ne,
                              __global fp *d_I)
{
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255.0f;
    }
}
